function sanitizeDocJson(doc: object): object {
  const escapeHtml = (str: string): string =>
    str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#x27;');

  return JSON.parse(
    JSON.stringify(doc, (_key, value) =>
      typeof value === 'string' ? escapeHtml(value) : value,
    ),
  );
}

